2	/**
3	 * Plugin Name:  BIT Cross-Blog Attachment Fix
4	 * Description:  Fixes cross-blog attachment resolution for blog 2 (/cultura/)
5	 *               accessing attachments stored in blog 1 (site principal).
6	 *               Covers: wp_get_attachment_url (lightbox, audio, video, download
7	 *               button), get_attached_file (download handler, SVG manager) e
8	 *               pré-população de cache para process_download e widget gallery.
9	 *               Complementa o Network Media Library, que já cobre
10	 *               wp_get_attachment_image_src().
11	 * Version:      1.2.2
12	 * Author:       Bureau IT
13	 * Network:      true
14	 *
15	 * NOTA: Plugin específico para multisite de 2 blogs (subdirectory mode) onde
16	 * o blog 1 (raiz) detém a mídia e o blog 2 (/cultura/) referencia esses IDs.
17	 * Todos os hooks verificam get_current_blog_id() !== 2 e retornam imediatamente
18	 * em instalações single-site ou com topologia diferente.
19	 */
20	
21	if ( ! defined( 'ABSPATH' ) ) {
22		exit;
23	}
24	
25	// ─────────────────────────────────────────────────────────────────────────────
26	// HELPER: pré-popula object cache + postmeta do blog 2 com dados do blog 1
27	// para uma lista de attachment IDs. Uma única switch_to_blog() por chamada.
28	// Usado pelos hooks de widget antes de renderizar (hooks 3 e 4).
29	// ─────────────────────────────────────────────────────────────────────────────
30	function bit_crossblog_warm_cache( array $ids ) : void {
31		static $warmed = [];
32	
33		$missing = array_filter( $ids, function ( $id ) use ( &$warmed ) {
34			if ( isset( $warmed[ $id ] ) ) return false;
35			$post = wp_cache_get( $id, 'posts' );
36			return ! $post || $post->post_type !== 'attachment';
37		} );
38	
39		if ( empty( $missing ) ) return;
40	
41		switch_to_blog( 1 );
42		update_meta_cache( 'post', $missing );
43		$b1_posts = [];
44		$b1_metas = [];
45		foreach ( $missing as $id ) {
46			$post = get_post( $id );
47			if ( $post && $post->post_type === 'attachment' ) {
48				$b1_posts[ $id ] = $post;
49				$b1_metas[ $id ] = wp_cache_get( $id, 'post_meta' );
50			}
51			$warmed[ $id ] = true;
52		}
53		restore_current_blog();
54	
55		// wp_cache_set após restore — blog_prefix=2, escreve no namespace correto
56		foreach ( $b1_posts as $id => $post ) {
57			wp_cache_set( $id, $post, 'posts' );
58			// Usa !== false para distinguir "meta vazia" (array) de "cache miss" (false).
59			// Sem isso, meta vazia não seria gravada e causaria query no namespace errado.
60			if ( $b1_metas[ $id ] !== false ) {
61				wp_cache_set( $id, $b1_metas[ $id ] ?: [], 'post_meta' );
62			}
63		}
64	}
65	
66	// ─────────────────────────────────────────────────────────────────────────────
67	// 1. Fix wp_get_attachment_url() para attachments cross-blog (blog 2 → blog 1).
68	//    Cobre: lightbox do Elementor (add_lightbox_data_attributes), JetElements
69	//    audio, video e download button (exibição do nome do arquivo).
70	//
71	//    wp_get_attachment_url() só aplica este filtro quando get_post() retorna o
72	//    objeto. Quando o cache do blog 2 é pré-populado (hooks 3/4) com dados do
73	//    blog 1, a função constrói uma URL com o upload dir do blog 2 (/sites/2/).
74	//    Este filtro recebe essa URL incorreta e a substitui pela correta do blog 1.
75	//    Também cobre IDs que chegam sem cache (chama switch_to_blog diretamente).
76	//    Cache estático $resolved/$failed evita switch_to_blog() repetido por ID.
77	// ─────────────────────────────────────────────────────────────────────────────
78	add_filter( 'wp_get_attachment_url', function ( $url, $post_id ) {
79		static $switched = false;
80		static $resolved = [];
81		static $failed   = [];
82	
83		if ( get_current_blog_id() !== 2 ) return $url;
84		if ( isset( $failed[ $post_id ] ) ) return $url;
85		if ( isset( $resolved[ $post_id ] ) ) return $resolved[ $post_id ];
86		if ( $switched ) return $url;
87	
88		// Se a URL já está correta (não vem do upload dir do blog 2), retorna
89		$b2_upload = '/wp-content/uploads/sites/2/';
90		if ( $url && strpos( $url, $b2_upload ) === false ) return $url;
91	
92		$switched = true;
93		$b1_url   = false;
94		try {
95			switch_to_blog( 1 );
96			$b1_url = wp_get_attachment_url( $post_id );
97		} catch ( \Throwable $e ) {
98			$failed[ $post_id ] = true;
99		} finally {
100			restore_current_blog();
101			$switched = false;
102		}
103	
104		if ( $b1_url ) {
105			$resolved[ $post_id ] = $b1_url;
106			return $b1_url;
107		}
108	
109		$failed[ $post_id ] = true;
110		return $url;
111	}, 999, 2 );
112	
113	// ─────────────────────────────────────────────────────────────────────────────
114	// 2. Fix get_attached_file() para attachments cross-blog (blog 2 → blog 1).
115	//    Cobre: JetElements download handler (get_file_size + process_download) e
116	//    SVG manager (cálculo de dimensions).
117	//
118	//    Quando o cache é pré-populado com dados do blog 1, get_attached_file()
119	//    constrói o path com o upload dir do blog 2 (/uploads/sites/2/). Este filtro
120	//    intercepta e substitui pelo path correto do blog 1.
121	//    Cache estático $resolved/$failed evita switch_to_blog() repetido por ID.
122	// ─────────────────────────────────────────────────────────────────────────────
123	add_filter( 'get_attached_file', function ( $file, $attachment_id ) {
124		static $switched = false;
125		static $resolved = [];
126		static $failed   = [];
127	
128		if ( get_current_blog_id() !== 2 ) return $file;
129		if ( isset( $failed[ $attachment_id ] ) ) return $file;
130		if ( isset( $resolved[ $attachment_id ] ) ) return $resolved[ $attachment_id ];
131		if ( $switched ) return $file;
132	
133		// Se o path já está correto (não usa o diretório do blog 2), retorna
134		$b2_upload_path = '/uploads/sites/2/';
135		if ( $file && strpos( $file, $b2_upload_path ) === false ) return $file;
136	
137		$switched = true;
138		$b1_file  = false;
139		try {
140			switch_to_blog( 1 );
141			$b1_file = get_attached_file( $attachment_id );
142		} catch ( \Throwable $e ) {
143			$failed[ $attachment_id ] = true;
144		} finally {
145			restore_current_blog();
146			$switched = false;
147		}
148	
149		if ( $b1_file ) {
150			$resolved[ $attachment_id ] = $b1_file;
151			return $b1_file;
152		}
153	
154		$failed[ $attachment_id ] = true;
155		return $file;
156	}, 999, 2 );
157	
158	// ─────────────────────────────────────────────────────────────────────────────
159	// 3. Pré-popula object cache do blog 2 com post + meta do blog 1 antes que
160	//    JetElements process_download() (init priority 99) chame get_post($id).
161	//    Sem isso, get_post() retorna null → Fatal Error PHP 8.
162	//    Hash estrutura: [ 'sha1hash' => post_id ] (gravada no blog 2 pelo widget).
163	//    update_meta_cache() chamado somente se o post existir no blog 1.
164	//    wp_cache_set() após restore_current_blog() — escreve no namespace do blog 2.
165	// ─────────────────────────────────────────────────────────────────────────────
166	add_action( 'init', function () {
167		if ( get_current_blog_id() !== 2 ) return;
168		if ( empty( $_GET['jet_download'] ) ) return;
169	
170		// Resolve hash → ID no blog 2 (onde a option foi gravada pelo widget)
171		$hashes = get_option( 'jet_elements_download_button_hashes', [] );
172		$hash   = sanitize_text_field( wp_unslash( $_GET['jet_download'] ) );
173		$id     = isset( $hashes[ $hash ] ) ? (int) $hashes[ $hash ] : 0;
174	
175		// Fallback: tenta ler do blog 1 (edge case: hash gerado no admin do blog 1).
176		// Executa sempre que o hash não foi encontrado no blog 2 — o blog 2 pode ter
177		// outros hashes válidos e ainda assim um hash específico ter sido gravado no
178		// admin do blog 1. A condição empty($hashes) era falso negativo nesse caso.
179		if ( ! $id ) {
180			switch_to_blog( 1 );
181			$hashes_b1 = get_option( 'jet_elements_download_button_hashes', [] );
182			restore_current_blog();
183			$id = isset( $hashes_b1[ $hash ] ) ? (int) $hashes_b1[ $hash ] : 0;
184		}
185	
186		if ( ! $id ) return;
187	
188		bit_crossblog_warm_cache( [ $id ] );
189	}, 5 );
190	
191	// ─────────────────────────────────────────────────────────────────────────────
192	// 4. Antes do render de widgets Elementor/JetElements, pré-popula o object cache
193	//    (namespace blog 2) com posts + meta de attachments do blog 1.
194	//    Garante que get_post($id) retorne correto → wp_get_attachment_url() funciona.
195	//
196	//    Widgets cobertos:
197	//    - gallery (Elementor): IDs em settings.galleries[].multiple_gallery[].id
198	//                           e settings.gallery[].id (single gallery type)
199	//    - jet-audio: ID em settings.self_url.id  (source=self_hosted)
200	//    - jet-video: ID em settings.self_hosted_url.id  (video_type=self_hosted)
201	//    - jet-download-button: ID em settings.file_attachment.id
202	// ─────────────────────────────────────────────────────────────────────────────
203	add_action( 'elementor/widget/before_render_content', function ( $widget ) {
204		if ( get_current_blog_id() !== 2 ) return;
205	
